from itertools import permutations
from collections import defaultdict

def canonical(peptide):
    n = len(peptide)
    rotations = [peptide[i:]+peptide[:i] for i in range(n)]
    reflections = [tuple(reversed(r)) for r in rotations]
    all = rotations + reflections
    return min(all)

counts = defaultdict(int)
for p in permutations(['A']*3 + ['K']*3 + ['G']*3 + ['P']*3):
    # Check no adjacent P's cyclically
    ok = True
    for i in range(12):
        if p[i] == 'P' and p[(i+1)%12] == 'P':
            ok = False
            break
    if ok:
        counts[canonical(p)] += 1

